 1	import React from 'react';
 2	
 3	import Loading from '@kubevirt-utils/components/Loading/Loading';
 4	import SearchItem from '@kubevirt-utils/components/SearchItem/SearchItem';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { updateVMCustomizeIT, vmSignal } from '@kubevirt-utils/store/customizeInstanceType';
 7	import {
 8	  Grid,
 9	  GridItem,
10	  PageSection,
11	  PageSectionVariants,
12	  Stack,
13	  Title,
14	} from '@patternfly/react-core';
15	import SSHTabAuthorizedSSHKey from '@virtualmachines/details/tabs/configuration/ssh/components/SSHTabAuthorizedSSHKey';
16	import SSHTabSSHAccess from '@virtualmachines/details/tabs/configuration/ssh/components/SSHTabSSHAccess';
17	
18	const CustomizeInstanceTypeSSHTab = () => {
19	  const { t } = useKubevirtTranslation();
20	  const vm = vmSignal.value;
21	
22	  if (!vm) {
23	    return <Loading />;
24	  }
25	
26	  return (
27	    <PageSection variant={PageSectionVariants.light}>
28	      <Title headingLevel="h2">
29	        <SearchItem id="ssh">{t('SSH settings')} </SearchItem>
30	      </Title>
31	      <Grid span={6}>
32	        <GridItem>
33	          <Stack hasGutter>
34	            <SSHTabSSHAccess isCustomizeInstanceType vm={vm} />
35	            <SSHTabAuthorizedSSHKey
36	              isCustomizeInstanceType
37	              onUpdateVM={updateVMCustomizeIT}
38	              vm={vm}
39	            />
40	          </Stack>
41	        </GridItem>
42	      </Grid>
43	    </PageSection>
44	  );
45	};
46	
47	export default CustomizeInstanceTypeSSHTab;

